package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.StringWriter;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithTrailingDelimiter() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = csvFormat.withTrailingDelimiter();

        // Then
        assertTrue(result.getTrailingDelimiter());
    }

    // Helper method to access private method using reflection
    private Object invokePrivateMethod(Object object, String methodName, Class<?>[] parameterTypes, Object[] parameters)
            throws Exception {
        java.lang.reflect.Method method = object.getClass().getDeclaredMethod(methodName, parameterTypes);
        method.setAccessible(true);
        return method.invoke(object, parameters);
    }
}
